import { defineStore } from "pinia";

export const useAuthStore = defineStore("auth", {
  state: () => ({
    role: localStorage.getItem("role") || "user", // Lấy role từ localStorage (mặc định là user)
  }),
  actions: {
    setRole(role) {
      this.role = role;
      localStorage.setItem("role", role);
    },
  },
});
